configuration.bnd:
Bundle-SymbolicName: ${project.artifactId} Bundle-Name: ${project.name} Bundle-Version: ${project.version}
# Consumer-facing facade API. Application bundles migrating off SLF4J # imports will be wired to this package by OSGi at resolve time. Export-Package: com.adobexp.log
# Hard veto on any package header AEMaaCS Code Quality rule S1874 would # flag as deprecated. The bundle uses only the SLF4J facade (public # org.slf4j API), java.nio.file / java.net.http to tail and push logs, # and the OSGi DS / Metatype annotations for wiring. No OSGi Log # Service, no SLF4J SPI/impl/helpers, no Logback. Import-Package: !ch.qos.logback.*,\ !org.apache.sling.commons.log.*,\ !org.slf4j.spi,\ !org.slf4j.helpers,\ !org.slf4j.impl,\ !org.osgi.service.log.*,\ !com.github.loki4j.*,\ org.slf4j;version="[1.7,2)",\ *
